const fs = require('node:fs');
const input = fs.readFileSync(0, 'utf8').trim();
function parse(text){const value=Number(text);if(!Number.isInteger(value))throw new TypeError('integer required',{cause:new Error('parse')});return value} try{console.log(parse(input)*2)}catch(error){console.log(`invalid:${error.cause?.constructor.name??'unknown'}`)}
